const data = $input.first().json;
const exportedAt = new Date(data.exportedAt || Date.now()).toLocaleString();
const summary = data.segmentSummary || {};
const topSegments = Object.entries(summary)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 15)
  .map(([name, count]) => `  ${name}: ${count}`)
  .join('\n');
const sample = (data.audiences || [])
  .slice(0, 10)
  .map((row) => {
    const tags = [...(row.segments || []), ...(row.interestTags || [])].slice(0, 4).join(', ');
    return `  ${row.email || row.identityKey} | orders ${row.orderCount} | spent ${row.totalSpent} | ${tags}`;
  })
  .join('\n');
const body = [
  `Recommendation Marketing Audiences (${exportedAt})`,
  '',
  `Identified customers with email: ${data.audienceCount || 0}`,
  '',
  'Top segments / interest tags:',
  topSegments || '  (none yet)',
  '',
  'Sample audience rows:',
  sample || '  (none yet — shoppers need checkout email + profile activity)',
  '',
  'Connect an Email / HTTP node here to sync audiences[] to your ESP.',
].join('\n');
return [{
  json: {
    subject: `Marketing Audiences Export - ${data.audienceCount || 0} customers`,
    body,
    audienceCount: data.audienceCount || 0,
    audiences: data.audiences || [],
    segmentSummary: summary,
  },
}];
